import React from "react";
import { ArrowUpRight, ArrowDownLeft, Sun, Moon } from "lucide-react";
import { formatCurrency } from "../helpers/helpers";

export default function HomeScreen({
  balance,
  savingsBalance,
  transactions = [],
  userName,
  openScreen,
  darkMode,
  setDarkMode
}) {
  return (
    <div className={`px-6 pb-24 min-h-screen animate-fade-in ${darkMode ? "bg-gray-900 text-white" : "bg-gray-50 text-gray-900"}`}>
      {/* Greeting + Dark Mode Toggle */}
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-bold">Hello, {userName} 👋</h1>
        <button
          onClick={() => setDarkMode(!darkMode)}
          className="p-2 rounded-full bg-gray-200 dark:bg-gray-700 text-gray-900 dark:text-white hover:opacity-80 transition"
        >
          {darkMode ? <Sun size={20} /> : <Moon size={20} />}
        </button>
      </div>

      {/* Total Balance Card */}
      <div className={`rounded-3xl p-6 shadow-lg mb-8 ${darkMode ? "bg-gray-800 text-white shadow-gray-700" : "bg-gradient-to-br from-emerald-600 to-teal-800 text-white shadow-emerald-200"}`}>
        <div className="flex justify-between items-start mb-2">
          <span className={`text-sm font-medium ${darkMode ? "text-gray-300" : "text-emerald-100"}`}>Total Balance</span>
          <span className="text-lg font-bold">Nest.</span>
        </div>
        <div className="text-4xl font-bold mb-4 tracking-tight">${formatCurrency(balance)}</div>

        {/* Savings Balance */}
        <p className={`font-medium mb-4 ${darkMode ? "text-gray-400" : "text-emerald-200"}`}>
          Savings: ${formatCurrency(savingsBalance)}
        </p>

        {/* Buttons */}
        <div className="flex gap-3">
          <button
            onClick={() => openScreen("Deposit")}
            className={`flex-1 py-2.5 rounded-xl flex items-center justify-center gap-2 font-medium transition ${
              darkMode ? "bg-gray-700 hover:bg-gray-600" : "bg-white/20 backdrop-blur-sm hover:bg-white/30"
            }`}
          >
            <ArrowUpRight className="w-4 h-4" /> Deposit
          </button>

          <button
            onClick={() => openScreen("Withdraw")}
            className={`flex-1 py-2.5 rounded-xl flex items-center justify-center gap-2 font-medium transition ${
              darkMode ? "bg-gray-700 hover:bg-gray-600" : "bg-white/20 backdrop-blur-sm hover:bg-white/30"
            }`}
          >
            <ArrowDownLeft className="w-4 h-4" /> Withdraw
          </button>
        </div>

        {/* Savings actions */}
        <div className="flex gap-3 mt-3">
          <button
            onClick={() => openScreen("SavingsDeposit")}
            className={`flex-1 py-2.5 rounded-xl flex items-center justify-center gap-2 font-medium transition ${
              darkMode ? "bg-gray-700 hover:bg-gray-600" : "bg-white/20 backdrop-blur-sm hover:bg-white/30"
            }`}
          >
            Save
          </button>

          <button
            onClick={() => openScreen("SavingsWithdraw")}
            className={`flex-1 py-2.5 rounded-xl flex items-center justify-center gap-2 font-medium transition ${
              darkMode ? "bg-gray-700 hover:bg-gray-600" : "bg-white/20 backdrop-blur-sm hover:bg-white/30"
            }`}
          >
            Withdraw Savings
          </button>
        </div>
      </div>

      {/* Recent Transactions */}
      <div>
        <div className="flex justify-between items-center mb-4">
          <h2 className={`font-bold text-lg ${darkMode ? "text-white" : "text-gray-800"}`}>Recent Transactions</h2>
          <button
            onClick={() => openScreen("Transactions")}
            className={`text-gray-400 ${darkMode ? "text-gray-300" : "text-gray-400"}`}
          >
            ▶
          </button>
        </div>

        <div className="space-y-4">
          {transactions.slice(0, 5).map((t) => (
            <div
              key={t.id}
              className={`flex items-center justify-between p-3 rounded-xl border cursor-pointer transition ${
                darkMode
                  ? "bg-gray-800 border-gray-700 hover:bg-gray-700"
                  : "bg-white border-gray-50 hover:bg-gray-50"
              }`}
              onClick={() => openScreen("TransactionReceipt", t)}
            >
              <div className="flex items-center gap-3">
                <div
                  className={`w-10 h-10 rounded-full flex items-center justify-center ${
                    t.type.includes("deposit")
                      ? darkMode
                        ? "bg-emerald-700 text-emerald-300"
                        : "bg-emerald-100 text-emerald-600"
                      : darkMode
                      ? "bg-red-700 text-red-300"
                      : "bg-red-100 text-red-600"
                  }`}
                >
                  {t.type.includes("deposit") ? <ArrowDownLeft className="w-5 h-5" /> : <ArrowUpRight className="w-5 h-5" />}
                </div>
                <div>
                  <p className={`font-semibold ${darkMode ? "text-white" : "text-gray-800"}`}>{t.title}</p>
                  <p className={`text-xs ${darkMode ? "text-gray-400" : "text-gray-400"}`}>{t.date}</p>
                </div>
              </div>
              <span
                className={`font-bold text-sm ${
                  t.type.includes("deposit")
                    ? darkMode
                      ? "text-emerald-400"
                      : "text-emerald-600"
                    : darkMode
                    ? "text-white"
                    : "text-gray-800"
                }`}
              >
                {t.type.includes("deposit") ? "+" : "-"}${formatCurrency(t.amount)}
              </span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
